import React, { useState, useRef } from 'react';

export default function ChatAssistant({ messages, onSendMessage, isLocked, user }) {
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef(null);

  const handleSend = () => {
    if (inputValue.trim() && !isLocked) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  const handleQuickPrompt = (text) => {
    if (!isLocked) {
      onSendMessage(text);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full bg-surface-container-low">
      {/* Assistant Header */}
      <div className="p-6 border-b border-surface-container flex items-center gap-4 bg-surface-container-lowest">
        <div className="w-10 h-10 rounded-xl bg-primary-container flex items-center justify-center text-white">
          <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>smart_toy</span>
        </div>
        <div>
          <h2 className="text-sm font-bold text-on-surface">Atelier Assistant</h2>
          <div className="flex items-center gap-1.5">
            <span className="w-2 h-2 rounded-full bg-secondary"></span>
            <span className="text-[0.7rem] font-semibold text-secondary uppercase tracking-widest">Active Now</span>
          </div>
        </div>
      </div>

      {/* Chat Messages Container */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.sender === user?.name ? 'justify-end' : ''}`}>
            {msg.sender !== user?.name && (
              <div className={`w-8 h-8 shrink-0 rounded-lg ${msg.role === 'SYSTEM' ? 'bg-primary/10 text-primary' : 'bg-secondary/10 text-secondary'} flex items-center justify-center`}>
                <span className="material-symbols-outlined text-sm">{msg.role === 'SYSTEM' ? 'auto_awesome' : 'person'}</span>
              </div>
            )}
            <div className={`${msg.sender === user?.name ? 'bg-primary text-white rounded-tr-none' : 'bg-surface-container-lowest border border-outline-variant/10 rounded-tl-none'} p-4 rounded-2xl shadow-sm text-sm leading-relaxed max-w-[85%]`}>
              {msg.sender !== user?.name && <div className="text-xs opacity-70 mb-1">{msg.sender}</div>}
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2 mb-3">
          <button 
            disabled={isLocked}
            onClick={() => handleQuickPrompt("Explain this formula")}
            className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1 rounded-full hover:bg-primary/10 hover:text-primary transition-colors disabled:opacity-50"
          >
            Explain Formula
          </button>
          <button 
            disabled={isLocked}
            onClick={() => handleQuickPrompt("Summarize this section")}
            className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1 rounded-full hover:bg-primary/10 hover:text-primary transition-colors disabled:opacity-50"
          >
            Summarize
          </button>
        </div>
        <div className="relative">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            disabled={isLocked}
            placeholder={isLocked ? "Chat is locked by teacher..." : "Ask your AI tutor..."}
            className={`w-full bg-slate-50 border-none rounded-xl pl-4 pr-12 py-3 text-sm focus:ring-2 focus:ring-primary outline-none transition-all ${isLocked ? 'cursor-not-allowed text-slate-400' : ''}`}
          />
          <button 
            onClick={handleSend}
            disabled={isLocked || !inputValue.trim()}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-primary hover:bg-primary/10 rounded-lg transition-colors disabled:opacity-30"
          >
            <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>send</span>
          </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';

export default function InteractiveQuiz({ block, userRole, isActive, onStart, onStop, onSubmit, results }) {
  const quizData = typeof block.content === 'string' ? JSON.parse(block.content) : block.content;
  const [selectedOption, setSelectedOption] = useState(null);
  const [hasSubmitted, setHasSubmitted] = useState(false);
  const [timeLeft, setTimeLeft] = useState(30);

  React.useEffect(() => {
    let timer;
    if (isActive && !hasSubmitted) {
      setTimeLeft(30);
      timer = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            clearInterval(timer);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isActive, hasSubmitted]);

  const handleSelect = (index) => {
    if (!isActive || hasSubmitted || userRole === 'TEACHER' || timeLeft === 0) return;
    setSelectedOption(index);
  };

  const handleSubmit = () => {
    if (selectedOption !== null && !hasSubmitted && timeLeft > 0) {
      onSubmit(block.id, selectedOption);
      setHasSubmitted(true);
    }
  };

  React.useEffect(() => {
    if (timeLeft === 0 && !hasSubmitted && isActive && userRole === 'STUDENT' && selectedOption !== null) {
      handleSubmit();
    }
  }, [timeLeft, hasSubmitted, isActive, userRole, selectedOption]);

  const totalVotes = results ? Object.values(results).reduce((a, b) => a + b, 0) : 0;

  return (
    <div className="relative group my-8">
      {isActive && <div className="absolute -inset-1 bg-gradient-to-r from-primary to-primary-container rounded-2xl blur opacity-25"></div>}
      <div className={`relative bg-surface-container-lowest p-8 rounded-xl shadow-lg space-y-6 border ${isActive ? 'border-primary/50' : 'border-outline-variant/30'}`}>

        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <h3 className="text-xl font-bold text-primary flex items-center gap-2">
              <span className="material-symbols-outlined">quiz</span>
              Live Pulse Quiz
            </h3>
            <p className="text-sm text-outline">
              {userRole === 'TEACHER' 
                ? 'Control this quiz for the class.' 
                : isActive 
                  ? 'Respond now!' 
                  : hasSubmitted 
                    ? 'Wait for next question...' 
                    : 'Get ready...'}
            </p>
          </div>

          <div className="flex items-center gap-3">
             {isActive && (
               <div className={`flex items-center gap-2 px-4 py-2 rounded-full font-mono text-lg font-bold ${timeLeft <= 5 ? 'bg-error text-white animate-bounce' : 'bg-primary/10 text-primary'}`}>
                 <span className="material-symbols-outlined text-sm">timer</span>
                 {timeLeft}s
               </div>
             )}

             {userRole === 'TEACHER' && (
               <div className="flex items-center gap-2">
                 {!isActive ? (
                   <button onClick={() => onStart(block.id)} className="bg-primary text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg active:scale-95 transition-all flex items-center gap-1">
                     <span className="material-symbols-outlined text-sm">play_arrow</span> Start Quiz
                   </button>
                 ) : (
                   <button onClick={() => onStop(block.id)} className="bg-error text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg active:scale-95 transition-all flex items-center gap-1">
                     <span className="material-symbols-outlined text-sm">stop</span> Finish Quiz
                   </button>
                 )}
               </div>
             )}
          </div>
        </div>

        <p className={`text-lg font-medium text-on-surface ${!isActive && userRole === 'STUDENT' && !hasSubmitted ? 'blur-sm select-none' : ''}`}>
          {quizData?.question || 'Untitled Question'}
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {(quizData?.options || []).map((opt, idx) => {
            const letter = String.fromCharCode(65 + idx);
            const isSelected = selectedOption === idx;

            // For teacher, or if student has submitted, show results optionally
            const votes = results ? (results[idx] || 0) : 0;
            const percentage = totalVotes > 0 ? Math.round((votes / totalVotes) * 100) : 0;

            return (
              <button 
                key={idx}
                onClick={() => handleSelect(idx)}
                disabled={!isActive || hasSubmitted || userRole === 'TEACHER'}
                className={`relative overflow-hidden flex items-center p-4 rounded-lg bg-surface border transition-all text-left group
                  ${isSelected ? 'border-primary ring-2 ring-primary/20 bg-primary/5' : 'border-outline-variant hover:border-primary/50'}
                  ${(!isActive || hasSubmitted || userRole === 'TEACHER') ? 'cursor-default' : 'cursor-pointer hover:bg-primary/5'}
                `}
                type="button"
              >
                {/* Result Bar background */}
                {(userRole === 'TEACHER' || hasSubmitted) && (
                  <div 
                    className="absolute left-0 top-0 bottom-0 bg-primary/10 transition-all duration-500 ease-out"
                    style={{ width: `${percentage}%` }}
                  ></div>
                )}

                <span className={`relative z-10 w-8 h-8 flex items-center justify-center rounded-full mr-4 font-bold text-sm transition-colors
                  ${isSelected ? 'bg-primary text-white' : 'bg-surface-container-high group-hover:bg-primary/20'}
                `}>
                  {letter}
                </span>
                <span className={`relative z-10 text-sm font-medium ${!isActive && userRole === 'STUDENT' && !hasSubmitted ? 'blur-sm select-none' : ''}`}>
                  {opt.text}
                </span>

                {(userRole === 'TEACHER' || hasSubmitted) && (
                  <div className="relative z-10 ml-auto flex items-center gap-3">
                    {opt.isCorrect && (
                      <span className="flex items-center gap-1 text-[10px] font-bold text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded uppercase tracking-wider">
                        Correct
                      </span>
                    )}
                    <span className="text-xs font-bold text-primary/70">
                      {percentage}% ({votes})
                    </span>
                  </div>
                )}
              </button>
            );
          })}
        </div>

        {isActive && userRole === 'STUDENT' && !hasSubmitted && (
          <div className="flex justify-end pt-2">
             <button 
                onClick={handleSubmit} 
                disabled={selectedOption === null}
                className="bg-primary text-white px-6 py-2 rounded-full font-bold shadow-md hover:shadow-lg active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 flex items-center gap-2"
              >
                Submit Answer <span className="material-symbols-outlined text-sm">send</span>
             </button>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { assignmentService } from '../services/api';
import useAuthStore from '../store/useAuthStore';

export default function AssignmentGradingPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuthStore();

  const [assignment, setAssignment] = useState(null);
  const [submissions, setSubmissions] = useState([]);
  const [selectedSubmission, setSelectedSubmission] = useState(null);
  const [loading, setLoading] = useState(true);
  const [gradingLoading, setGradingLoading] = useState(false);
  const [error, setError] = useState('');

  // Grading form state
  const [grade, setGrade] = useState('');
  const [feedback, setFeedback] = useState('');

  useEffect(() => {
    if (!user || user.role !== 'TEACHER') {
      navigate('/dashboard');
      return;
    }
    fetchData();
  }, [id, user, navigate]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [assignmentData, submissionsData] = await Promise.all([
        assignmentService.getById(id),
        assignmentService.getSubmissions(id)
      ]);
      setAssignment(assignmentData);
      setSubmissions(submissionsData);
      if (submissionsData.length > 0) {
        handleSelectSubmission(submissionsData[0]);
      }
    } catch (err) {
      console.error('Failed to fetch grading data:', err);
      setError('Failed to load submissions');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectSubmission = (sub) => {
    setSelectedSubmission(sub);
    setGrade(sub.grade || '');
    setFeedback(sub.feedback || '');
  };

  const handleSaveGrade = async () => {
    if (!selectedSubmission) return;
    try {
      setGradingLoading(true);
      await assignmentService.grade(selectedSubmission.id, { grade, feedback });
      // Update local state
      setSubmissions(prev => prev.map(s => s.id === selectedSubmission.id ? { ...s, grade: parseFloat(grade), feedback } : s));
      setSelectedSubmission(prev => ({ ...prev, grade: parseFloat(grade), feedback }));
    } catch (err) {
      console.error('Failed to save grade:', err);
      alert('Failed to save grade');
    } finally {
      setGradingLoading(false);
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-surface">Loading submissions...</div>;

  return (
    <div className="bg-surface text-on-surface h-screen flex flex-col overflow-hidden">
      {/* Top Header */}
      <header className="bg-white/80 backdrop-blur-md fixed top-0 w-full z-50 border-b border-slate-100 shadow-sm h-16 flex items-center px-6">
        <div className="flex items-center gap-4 flex-1">
          <button onClick={() => navigate(-1)} className="material-symbols-outlined text-outline hover:bg-surface-container-low p-2 rounded-full transition-colors">arrow_back</button>
          <div className="flex flex-col">
            <h1 className="text-lg font-bold text-slate-900 truncate max-w-md">{assignment?.title}</h1>
            <span className="text-[10px] font-bold text-outline-variant uppercase tracking-wider">Grading Dashboard</span>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="text-right hidden sm:block">
            <p className="text-xs font-bold text-on-surface">{user?.name}</p>
            <p className="text-[10px] text-primary uppercase font-bold tracking-tighter">Teacher</p>
          </div>
          <div className="h-8 w-8 rounded-full bg-primary flex items-center justify-center text-white text-xs font-bold">
            {user?.name?.charAt(0)}
          </div>
        </div>
      </header>

      <main className="flex-1 flex pt-16 overflow-hidden">
        {/* Left Sidebar: Students */}
        <aside className="w-80 flex-shrink-0 bg-surface-container-low border-r border-outline-variant/15 flex flex-col">
          <div className="p-4 border-b border-outline-variant/15">
            <div className="flex items-center justify-between mb-4">
              <span className="text-xs font-bold text-outline-variant uppercase tracking-widest">{submissions.length} Submissions</span>
            </div>
            <div className="relative">
              <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-outline-variant text-sm">search</span>
              <input 
                className="w-full bg-white border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-primary transition-all outline-none" 
                placeholder="Search students..." 
                type="text"
              />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto no-scrollbar p-2 space-y-1">
            {submissions.map(sub => (
              <div 
                key={sub.id} 
                onClick={() => handleSelectSubmission(sub)}
                className={`flex items-center gap-3 p-4 rounded-xl cursor-pointer transition-all ${selectedSubmission?.id === sub.id ? 'bg-white shadow-sm ring-1 ring-primary/10' : 'hover:bg-white/50'}`}
              >
                <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-sm">
                  {sub.student?.name?.charAt(0)}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold truncate">{sub.student?.name}</p>
                  <p className={`text-[10px] font-bold uppercase tracking-tighter ${sub.grade !== null ? 'text-secondary' : 'text-tertiary'}`}>
                    {sub.grade !== null ? `Graded: ${sub.grade}/100` : 'Turned In'}
                  </p>
                </div>
                {sub.grade !== null && <span className="material-symbols-outlined text-secondary text-sm">check_circle</span>}
              </div>
            ))}
            {submissions.length === 0 && <div className="p-8 text-center text-xs text-outline-variant italic">No submissions yet</div>}
          </div>
        </aside>

        {/* Center Content: View Submission */}
        <section className="flex-1 bg-surface-dim/10 overflow-y-auto p-8 flex flex-col items-center">
          {selectedSubmission ? (
            <div className="max-w-4xl w-full bg-white shadow-xl rounded-2xl min-h-[800px] flex flex-col relative overflow-hidden">
               <div className="absolute top-0 left-0 w-full h-1.5 signature-gradient"></div>
               <div className="p-12 space-y-8">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <h2 className="text-3xl font-bold text-on-surface">{selectedSubmission.student?.name}'s Submission</h2>
                      <p className="text-sm text-outline-variant">Submitted on {new Date(selectedSubmission.submitted_at).toLocaleString()}</p>
                    </div>
                  </div>

                  <div className="bg-surface-container-lowest border border-outline-variant/30 rounded-2xl p-8 min-h-[400px]">
                    {selectedSubmission.file_url ? (
                       <div className="space-y-4">
                          <p className="text-on-surface-variant leading-relaxed">
                            {selectedSubmission.file_url}
                          </p>
                          <div className="p-4 bg-primary/5 rounded-xl border border-primary/20 flex items-center gap-3">
                            <span className="material-symbols-outlined text-primary">description</span>
                            <div className="flex-1">
                               <p className="text-sm font-bold text-on-surface">Attached Document</p>
                               <p className="text-xs text-outline-variant">Student submitted a text/link document.</p>
                            </div>
                            <a href={selectedSubmission.file_url} target="_blank" rel="noreferrer" className="text-primary font-bold text-xs hover:underline">Open Link</a>
                          </div>
                       </div>
                    ) : (
                      <p className="text-outline-variant italic">No content provided in this submission.</p>
                    )}
                  </div>
               </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-outline-variant gap-4">
               <span className="material-symbols-outlined text-6xl opacity-20">assignment_turned_in</span>
               <p className="font-medium">Select a student to view their submission</p>
            </div>
          )}
        </section>

        {/* Right Sidebar: Grading */}
        <aside className="w-80 flex-shrink-0 bg-white border-l border-outline-variant/15 flex flex-col p-6 gap-8">
          <div className="space-y-4">
            <h3 className="text-[10px] font-bold text-outline-variant uppercase tracking-widest">Grading</h3>
            <div className="flex items-end gap-3">
              <div className="relative flex-1">
                <label className="text-[10px] font-bold text-primary uppercase absolute -top-2.5 left-2 bg-white px-1">Score</label>
                <input 
                  className="w-full text-3xl font-bold border-b-2 border-primary focus:border-primary-container focus:ring-0 p-2 bg-transparent outline-none transition-colors" 
                  type="number" 
                  value={grade}
                  onChange={(e) => setGrade(e.target.value)}
                  placeholder="--"
                />
              </div>
              <span className="text-2xl font-bold text-outline-variant pb-2">/ 100</span>
            </div>
          </div>

          <div className="space-y-4 flex-1 flex flex-col">
            <h3 className="text-[10px] font-bold text-outline-variant uppercase tracking-widest">Private Feedback</h3>
            <div className="flex-1 flex flex-col">
              <textarea 
                className="w-full bg-surface-container-high border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-primary min-h-[200px] resize-none outline-none" 
                placeholder="Write feedback for the student..."
                value={feedback}
                onChange={(e) => setFeedback(e.target.value)}
              ></textarea>
            </div>
          </div>

          <div className="pt-6 border-t border-outline-variant/15 flex flex-col gap-3">
            <button 
              onClick={handleSaveGrade}
              disabled={!selectedSubmission || gradingLoading}
              className="w-full py-4 rounded-full signature-gradient text-white font-bold shadow-lg hover:shadow-xl transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {gradingLoading ? <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span> : 'Return to Student'}
            </button>
            <button className="w-full py-3 rounded-full text-outline-variant font-bold text-sm hover:bg-surface-container-high transition-colors">
              Save Draft
            </button>
          </div>
        </aside>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Link, useParams, useNavigate } from 'react-router-dom';
import { assignmentService } from '../services/api';
import useAuthStore from '../store/useAuthStore';

export default function AssignmentView() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuthStore();
  const [assignment, setAssignment] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [submissionContent, setSubmissionContent] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }
    fetchAssignment();
  }, [id, user, navigate]);

  const fetchAssignment = async () => {
    try {
      setLoading(true);
      const data = await assignmentService.getById(id);
      setAssignment(data);
    } catch (err) {
      console.error('Failed to fetch assignment:', err);
      setError(err.response?.data?.error || 'Failed to load assignment');
    } finally {
      setLoading(false);
    }
  };

  const handleTurnIn = async () => {
    if (!submissionContent.trim()) return;
    try {
      setSubmitting(true);
      await assignmentService.submit(id, submissionContent);
      setSubmitted(true);
      await fetchAssignment(); // Refresh to show submission status
    } catch (err) {
      console.error('Failed to submit:', err);
      alert('Failed to submit assignment');
    } finally {
      setSubmitting(false);
    }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return 'No due date';
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit' });
  };

  if (loading) {
    return (
      <div className="bg-surface text-on-surface min-h-screen flex items-center justify-center">
        <p className="text-on-surface-variant text-lg">Loading assignment...</p>
      </div>
    );
  }

  if (error || !assignment) {
    return (
      <div className="bg-surface text-on-surface min-h-screen flex flex-col items-center justify-center gap-4">
        <span className="material-symbols-outlined text-5xl text-slate-300">error</span>
        <p className="text-on-surface-variant text-lg">{error || 'Assignment not found'}</p>
        <Link to="/dashboard" className="text-primary font-semibold hover:underline">Back to Dashboard</Link>
      </div>
    );
  }

  return (
    <div className="bg-surface text-on-surface antialiased min-h-screen">
      {/* TopAppBar */}
      <header className="fixed top-0 w-full z-50 bg-white/80 backdrop-blur-md border-b border-slate-100 shadow-sm font-['Inter'] antialiased">
        <div className="flex justify-between items-center px-6 h-16 w-full max-w-screen-2xl mx-auto">
          <div className="flex items-center gap-8">
            <Link to="/dashboard" className="text-xl font-semibold text-slate-900">Academic Atelier</Link>
            <nav className="hidden md:flex items-center space-x-6">
              <Link to="/dashboard" className="text-slate-500 hover:text-slate-900 transition-colors">Home</Link>
              <span className="text-blue-600 border-b-2 border-blue-600 pb-2">Classwork</span>
            </nav>
          </div>
          <div className="flex items-center gap-4">
            <button className="p-2 text-slate-500 hover:bg-slate-50 rounded-full transition-colors" type="button">
              <span className="material-symbols-outlined">apps</span>
            </button>
            <div className="h-8 w-8 rounded-full bg-primary flex items-center justify-center text-white text-sm font-bold">
              {user?.name?.charAt(0) || 'U'}
            </div>
          </div>
        </div>
      </header>

      <main className="pt-24 pb-12 px-6 max-w-screen-xl mx-auto">
        {/* Back Navigation */}
        <div className="mb-8">
          <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-primary font-medium hover:underline group">
            <span className="material-symbols-outlined text-sm transition-transform group-hover:-translate-x-1">arrow_back</span>
            Back to Classwork
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
          {/* Main Content Area */}
          <div className="lg:col-span-8">
            {/* Assignment Header */}
            <div className="flex items-start gap-5 mb-10">
              <div className="w-12 h-12 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                <span className="material-symbols-outlined text-white" style={{ fontVariationSettings: "'FILL' 1" }}>assignment</span>
              </div>
              <div className="flex-grow">
                <h1 className="text-[2.5rem] font-bold tracking-tight text-on-surface leading-tight mb-2">{assignment.title}</h1>
                <div className="flex flex-wrap items-center gap-x-6 gap-y-2 mt-2">
                  <div className="flex items-center gap-1.5 text-on-surface-variant">
                    <span className="text-sm">Class: {assignment.class?.name || 'Unknown'}</span>
                  </div>
                  <div className="text-sm font-bold text-tertiary">
                    {assignment.due_date ? `Due ${formatDate(assignment.due_date)}` : 'No due date'}
                  </div>
                </div>
              </div>
            </div>

            {/* Assignment Body */}
            <div className="space-y-8">
              {assignment.description ? (
                <section>
                  <div className="prose prose-slate max-w-none text-on-surface leading-relaxed text-lg">
                    <p>{assignment.description}</p>
                  </div>
                </section>
              ) : (
                <section className="bg-surface-container-low rounded-xl p-8 text-center">
                  <p className="text-slate-400 italic">No description provided</p>
                </section>
              )}

              {/* Attachments */}
              {assignment.attachment_url && (
                <section>
                  <h3 className="text-sm font-bold uppercase tracking-widest text-on-surface-variant mb-6">Attachments</h3>
                  <a className="flex items-center gap-4 p-4 rounded-xl border border-outline-variant hover:bg-surface-container-low transition-all group" href={assignment.attachment_url} target="_blank" rel="noreferrer">
                    <div className="w-12 h-12 bg-blue-50 rounded-lg flex items-center justify-center text-blue-600">
                      <span className="material-symbols-outlined text-3xl">description</span>
                    </div>
                    <div className="flex-grow overflow-hidden">
                      <p className="text-sm font-bold text-on-surface truncate">Attachment</p>
                      <p className="text-xs text-on-surface-variant">Click to open</p>
                    </div>
                    <span className="material-symbols-outlined text-outline-variant group-hover:text-primary transition-colors">open_in_new</span>
                  </a>
                </section>
              )}
            </div>
          </div>

          {/* Sidebar */}
          <div className="lg:col-span-4 space-y-6">
            {/* Your Work Card */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-slate-100 sticky top-24">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-on-surface">Your work</h2>
                {(assignment.submissions?.length > 0 || submitted) ? (
                  <span className="text-xs font-bold uppercase tracking-widest text-secondary">Submitted</span>
                ) : (
                  <span className="text-xs font-bold uppercase tracking-widest text-tertiary">Assigned</span>
                )}
              </div>

              <div className="space-y-4">
                {(assignment.submissions?.length > 0 || submitted) ? (
                  <div className="p-4 bg-secondary/5 rounded-xl border border-secondary/20">
                    <p className="text-sm font-bold text-secondary mb-1">Success!</p>
                    <p className="text-xs text-on-surface-variant">Your work has been turned in.</p>
                    {assignment.submissions?.[0]?.grade !== null && (
                      <div className="mt-4 pt-4 border-t border-secondary/10">
                        <p className="text-xs font-bold text-on-surface-variant uppercase tracking-widest mb-2">Grade</p>
                        <p className="text-2xl font-bold text-secondary">{assignment.submissions[0].grade} / 100</p>
                        {assignment.submissions[0].feedback && (
                          <div className="mt-2 p-3 bg-white rounded-lg text-xs italic text-on-surface-variant">
                            "{assignment.submissions[0].feedback}"
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                ) : (
                  <>
                    <textarea 
                      className="w-full bg-surface-container-high border-none rounded-xl p-3 text-sm focus:ring-2 focus:ring-primary min-h-[120px] resize-none outline-none" 
                      placeholder="Paste your submission link or text here..."
                      value={submissionContent}
                      onChange={(e) => setSubmissionContent(e.target.value)}
                    ></textarea>
                    <button 
                      onClick={handleTurnIn}
                      disabled={!submissionContent.trim() || submitting}
                      className="w-full py-3 px-4 rounded-full signature-gradient text-white font-bold shadow-md hover:shadow-lg transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2" 
                      type="button"
                    >
                      {submitting ? <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span> : 'Turn in'}
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { assignmentService, lessonService } from '../services/api';
import useAuthStore from '../store/useAuthStore';
import TopNavBar from '../components/TopNavBar';
import Sidebar from '../components/Sidebar';
import api from '../services/api';

export default function ClassStreamPage() {
  const location = useLocation();
  const navigate = useNavigate();
  const searchParams = new URLSearchParams(location.search);
  const classId = searchParams.get('classId');
  const { user } = useAuthStore();

  const [classData, setClassData] = useState(null);
  const [assignments, setAssignments] = useState([]);
  const [lessons, setLessons] = useState([]);
  const [loading, setLoading] = useState(true);

  // Create assignment modal
  const [showCreateAssignment, setShowCreateAssignment] = useState(false);
  const [assignTitle, setAssignTitle] = useState('');
  const [assignDesc, setAssignDesc] = useState('');
  const [assignDue, setAssignDue] = useState('');
  const [createError, setCreateError] = useState('');
  const [createLoading, setCreateLoading] = useState(false);

  // Create lesson modal
  const [showCreateLesson, setShowCreateLesson] = useState(false);
  const [lessonTitle, setLessonTitle] = useState('');
  const [lessonCreateError, setLessonCreateError] = useState('');
  const [lessonCreateLoading, setLessonCreateLoading] = useState(false);

  // Generate AI lesson modal
  const [showGenerateAi, setShowGenerateAi] = useState(false);
  const [aiTopic, setAiTopic] = useState('');
  const [aiGrade, setAiGrade] = useState('High School');
  const [aiDuration, setAiDuration] = useState('30');
  const [aiReferenceContent, setAiReferenceContent] = useState('');
  const [aiError, setAiError] = useState('');
  const [aiLoading, setAiLoading] = useState(false);

  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }
    if (!classId) {
      navigate('/dashboard');
      return;
    }
    fetchData();
  }, [classId, user, navigate]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [assignData, lessonData] = await Promise.all([
        assignmentService.getByClass(classId),
        lessonService.getByClass(classId)
      ]);
      setAssignments(assignData);
      setLessons(lessonData);
    } catch (err) {
      console.error('Failed to fetch class data:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateAssignment = async (e) => {
    e.preventDefault();
    setCreateError('');
    setCreateLoading(true);
    try {
      await assignmentService.create({
        class_id: classId,
        title: assignTitle,
        description: assignDesc,
        due_date: assignDue || null
      });
      setShowCreateAssignment(false);
      setAssignTitle('');
      setAssignDesc('');
      setAssignDue('');
      await fetchData();
    } catch (err) {
      setCreateError(err.response?.data?.error || 'Failed to create assignment');
    } finally {
      setCreateLoading(false);
    }
  };

  const handleCreateLesson = async (e) => {
    e.preventDefault();
    setLessonCreateError('');
    setLessonCreateLoading(true);
    try {
      const newLesson = await lessonService.create({
        class_id: classId,
        title: lessonTitle
      });
      setShowCreateLesson(false);
      setLessonTitle('');
      await fetchData();
      // Optionally navigate directly to the editor:
      // navigate(`/lesson/edit?lessonId=${newLesson.id}`);
    } catch (err) {
      setLessonCreateError(err.response?.data?.error || 'Failed to create lesson');
    } finally {
      setLessonCreateLoading(false);
    }
  };

  const handleGenerateAILesson = async (e) => {
    e.preventDefault();
    setAiError('');
    setAiLoading(true);
    try {
      // 1. Ask OpenRouter to draft the lesson JSON
      const generatedData = await lessonService.generateAi({
        topic: aiTopic,
        gradeLevel: aiGrade,
        targetDuration: aiDuration,
        referenceContent: aiReferenceContent
      });

      // 2. Create the empty lesson record in the DB to get an ID
      const newLesson = await lessonService.create({
        class_id: classId,
        title: generatedData.title || `Lesson on ${aiTopic}`
      });

      // 3. Update the lesson with the generated blocks
      await lessonService.update(newLesson.id, {
        status: 'DRAFT',
        blocks: generatedData.blocks || []
      });

      setShowGenerateAi(false);
      setAiTopic('');
      await fetchData();

      // Navigate to the editor so the teacher can review the AI generated content
      navigate(`/lesson/edit?lessonId=${newLesson.id}`);
    } catch (err) {
      setAiError(err.response?.data?.error || err.message || 'Failed to generate AI lesson');
    } finally {
      setAiLoading(false);
    }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return '';
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  if (loading) {
    return (
      <div className="bg-background text-on-background min-h-screen">
        <TopNavBar />
        <div className="flex">
          <Sidebar />
          <main className="pt-16 lg:pl-64 min-h-screen flex items-center justify-center w-full">
            <p className="text-on-surface-variant text-lg">Loading class data...</p>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-background text-on-background min-h-screen">
      <TopNavBar />

      <div className="flex">
        <Sidebar />

      {/* Main Content Area */}
      <main className="pt-16 lg:pl-64 min-h-screen">
        <div className="max-w-5xl mx-auto px-6 py-8">
          {/* Hero Banner */}
          <section className="relative h-64 rounded-xl overflow-hidden mb-8 shadow-sm group">
            <div className="absolute inset-0 bg-secondary">
              <img alt="Class Banner" className="w-full h-full object-cover mix-blend-overlay opacity-40" src="https://lh3.googleusercontent.com/aida-public/AB6AXuDGNr4QwSQkx9fnLMJDGQ1e2oiUrchCxbWdeFB_e6OsdIMlIQTEQO0Q__FHEepLna6OC9SFvDmB_Gu0dMJoy4o8obaajklKyNvXsKK1CDiFFUJBxZoigblHzvC2uEOQQHA0RwQoHbwQgqS8QjOiTPpJDLNN0I3aYx9kOZnY0NGXv7IR6f9TH2RYg5dLNgECIZd7LBmGGrrPcQtYNncF93l3GImp7OlA93KJiM7F1F2csG4nd4eBC0uJ_OlsBoUm-d9dbyj3QeZFBQY" />
            </div>
            <div className="absolute bottom-6 left-6 text-white">
              <h2 className="text-4xl font-bold tracking-tight">Class Stream</h2>
              <p className="text-xl opacity-90">Assignments & Lessons</p>
            </div>
            <button className="absolute top-4 right-4 bg-white/20 backdrop-blur-md p-2 rounded-full text-white hover:bg-white/30 transition-colors" type="button">
              <span className="material-symbols-outlined">info</span>
            </button>
          </section>

          <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
            {/* Left Column: Upcoming */}
            <aside className="lg:col-span-1">
              <div className="bg-surface-container-lowest rounded-xl p-6 shadow-sm border border-slate-100/10">
                <h3 className="text-sm font-semibold text-on-surface uppercase tracking-wider mb-4">Upcoming</h3>
                <div className="space-y-4">
                  {assignments.filter(a => a.due_date && new Date(a.due_date) > new Date()).slice(0, 3).map(a => (
                    <div key={a.id} className="group cursor-pointer">
                      <div className="flex flex-col items-end gap-2">
                        <span className="text-xs font-bold text-tertiary">Due {formatDate(a.due_date)}</span>
                        {user?.role === 'TEACHER' && (
                          <Link 
                            to={`/assignment/${a.id}/grade`}
                            className="text-[10px] font-bold uppercase tracking-widest text-primary hover:bg-primary/5 px-2 py-1 rounded border border-primary/20 transition-colors"
                          >
                            Grade Submissions
                          </Link>
                        )}
                      </div>
                      <Link to={`/assignment/${a.id}`} className="text-sm text-slate-700 font-medium group-hover:text-primary transition-colors block">{a.title}</Link>
                    </div>
                  ))}
                  {assignments.filter(a => a.due_date && new Date(a.due_date) > new Date()).length === 0 && (
                    <p className="text-sm text-slate-400 italic">No upcoming deadlines</p>
                  )}
                </div>
              </div>
            </aside>

            {/* Center Column: Stream Feed */}
            <div className="lg:col-span-3 space-y-6">
              {/* Assignments Section */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg font-bold text-on-surface flex items-center gap-2">
                    <span className="material-symbols-outlined text-primary">assignment</span>
                    Assignments
                  </h3>
                  {user?.role === 'TEACHER' && (
                    <button
                      onClick={() => { setCreateError(''); setShowCreateAssignment(true); }}
                      className="flex items-center gap-1 text-sm font-semibold text-primary hover:bg-primary/5 px-3 py-1.5 rounded-full transition-colors"
                    >
                      <span className="material-symbols-outlined text-sm">add</span>
                      New Assignment
                    </button>
                  )}
                </div>
                {assignments.length > 0 ? assignments.map(assignment => (
                  <Link key={assignment.id} to={`/assignment/${assignment.id}`} className="block">
                    <article className="bg-surface-container-lowest rounded-xl shadow-sm border border-slate-100/10 p-6 hover:shadow-md transition-all cursor-pointer group">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-primary flex items-center justify-center text-white">
                          <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>assignment</span>
                        </div>
                        <div className="flex-1">
                          <p className="text-sm font-bold text-slate-900 group-hover:text-primary transition-colors">{assignment.title}</p>
                          <p className="text-xs text-slate-500">
                             {assignment.due_date ? `Due ${formatDate(assignment.due_date)}` : 'No due date'}
                             {assignment.description && ` ΓÇó ${assignment.description.substring(0, 60)}...`}
                          </p>
                        </div>
                        {user?.role === 'TEACHER' && (
                          <Link 
                            to={`/assignment/${assignment.id}/grade`}
                            onClick={(e) => e.stopPropagation()}
                            className="text-[10px] font-bold uppercase tracking-widest text-primary hover:bg-primary/5 px-2 py-1 rounded-full border border-primary/20 transition-colors"
                          >
                            Grade
                          </Link>
                        )}
                        <span className="material-symbols-outlined text-slate-300 group-hover:text-primary transition-colors">chevron_right</span>
                      </div>
                    </article>
                  </Link>
                )) : (
                  <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-slate-100/10 p-8 text-center">
                    <span className="material-symbols-outlined text-4xl text-slate-300 mb-2 block">assignment</span>
                    <p className="text-slate-400 text-sm">No assignments yet</p>
                  </div>
                )}
              </div>

              {/* Lessons Section */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg font-bold text-on-surface flex items-center gap-2">
                    <span className="material-symbols-outlined text-secondary">auto_stories</span>
                    Lessons
                  </h3>
                  {user?.role === 'TEACHER' && (
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => { setAiError(''); setShowGenerateAi(true); }}
                        className="flex items-center gap-1 text-sm font-semibold signature-gradient text-white shadow hover:shadow-lg px-3 py-1.5 rounded-full transition-all active:scale-95"
                      >
                        <span className="material-symbols-outlined text-sm">magic_button</span>
                        Generate Lesson with AI
                      </button>
                      <button
                        onClick={() => { setLessonCreateError(''); setShowCreateLesson(true); }}
                        className="flex items-center gap-1 text-sm font-semibold text-secondary hover:bg-secondary/5 px-3 py-1.5 rounded-full transition-colors"
                      >
                        <span className="material-symbols-outlined text-sm">add</span>
                        Manual Lesson
                      </button>
                    </div>
                  )}
                </div>
                {lessons.length > 0 ? lessons.map(lesson => (
                  <Link key={lesson.id} to={user?.role === 'TEACHER' ? `/lesson/edit?lessonId=${lesson.id}` : `/lesson/live?lessonId=${lesson.id}`} className="block">
                    <article className="bg-surface-container-lowest rounded-xl shadow-sm border border-slate-100/10 p-6 hover:shadow-md transition-all cursor-pointer group">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-secondary flex items-center justify-center text-white">
                          <span className="material-symbols-outlined">auto_stories</span>
                        </div>
                        <div className="flex-1">
                          <p className="text-sm font-bold text-slate-900 group-hover:text-secondary transition-colors">{lesson.title}</p>
                          <p className="text-xs text-slate-500">
                            {lesson.status === 'LIVE' && <span className="text-tertiary font-bold">ΓùÅ LIVE</span>}
                            {lesson.status === 'DRAFT' && <span className="text-slate-400">Draft</span>}
                            {lesson.status === 'PUBLISHED' && <span className="text-secondary">Published</span>}
                            {' ΓÇó '}{formatDate(lesson.created_at)}
                          </p>
                        </div>
                        <span className="material-symbols-outlined text-slate-300 group-hover:text-secondary transition-colors">chevron_right</span>
                      </div>
                    </article>
                  </Link>
                )) : (
                  <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-slate-100/10 p-8 text-center">
                    <span className="material-symbols-outlined text-4xl text-slate-300 mb-2 block">auto_stories</span>
                    <p className="text-slate-400 text-sm">No lessons yet</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>
      </div>

      {/* FAB for Teachers */}
      {user?.role === 'TEACHER' && (
        <button
          onClick={() => { setCreateError(''); setShowCreateAssignment(true); }}
          className="fixed bottom-8 right-8 w-14 h-14 bg-primary text-white rounded-full shadow-lg hover:shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center z-50"
        >
          <span className="material-symbols-outlined text-3xl">add</span>
        </button>
      )}

      {/* Create Assignment Modal */}
      {showCreateAssignment && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/40 backdrop-blur-sm" onClick={() => setShowCreateAssignment(false)}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 p-8" onClick={e => e.stopPropagation()}>
            <h2 className="text-2xl font-bold text-on-surface mb-2">Create Assignment</h2>
            <p className="text-sm text-on-surface-variant mb-6">Add a new assignment for your class.</p>
            {createError && <div className="text-error text-sm mb-4 bg-error-container/30 p-3 rounded-lg">{createError}</div>}
            <form onSubmit={handleCreateAssignment} className="space-y-5">
              <div>
                <label className="block text-xs font-semibold text-on-surface-variant mb-1 uppercase tracking-wider">Title *</label>
                <input
                  type="text"
                  value={assignTitle}
                  onChange={(e) => setAssignTitle(e.target.value)}
                  required
                  placeholder="e.g., Chapter 3 Review"
                  className="w-full bg-surface-container-high border-b-2 border-outline/50 focus:border-primary focus:ring-0 px-3 py-3 transition-colors outline-none text-on-surface rounded-t-lg"
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-on-surface-variant mb-1 uppercase tracking-wider">Description</label>
                <textarea
                  value={assignDesc}
                  onChange={(e) => setAssignDesc(e.target.value)}
                  placeholder="Assignment instructions..."
                  rows={3}
                  className="w-full bg-surface-container-high border-b-2 border-outline/50 focus:border-primary focus:ring-0 px-3 py-3 transition-colors outline-none text-on-surface rounded-t-lg resize-none"
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-on-surface-variant mb-1 uppercase tracking-wider">Due Date</label>
                <input
                  type="datetime-local"
                  value={assignDue}
                  onChange={(e) => setAssignDue(e.target.value)}
                  className="w-full bg-surface-container-high border-b-2 border-outline/50 focus:border-primary focus:ring-0 px-3 py-3 transition-colors outline-none text-on-surface rounded-t-lg"
                />
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowCreateAssignment(false)} className="flex-1 py-3 rounded-full border-2 border-outline/30 text-on-surface font-semibold hover:bg-surface-container-high transition-colors">Cancel</button>
                <button type="submit" disabled={createLoading} className="flex-1 py-3 rounded-full signature-gradient text-white font-semibold shadow-lg hover:shadow-xl transition-all active:scale-95 disabled:opacity-50">
                  {createLoading ? 'Creating...' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Create Lesson Modal */}
      {showCreateLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/40 backdrop-blur-sm" onClick={() => setShowCreateLesson(false)}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md mx-4 p-8" onClick={e => e.stopPropagation()}>
            <h2 className="text-2xl font-bold text-on-surface mb-2">Create Lesson</h2>
            <p className="text-sm text-on-surface-variant mb-6">Create a new interactive lesson for your class.</p>
            {lessonCreateError && <div className="text-error text-sm mb-4 bg-error-container/30 p-3 rounded-lg">{lessonCreateError}</div>}
            <form onSubmit={handleCreateLesson} className="space-y-5">
              <div>
                <label className="block text-xs font-semibold text-on-surface-variant mb-1 uppercase tracking-wider">Lesson Title *</label>
                <input
                  type="text"
                  value={lessonTitle}
                  onChange={(e) => setLessonTitle(e.target.value)}
                  required
                  placeholder="e.g., Introduction to Neural Networks"
                  className="w-full bg-surface-container-high border-b-2 border-outline/50 focus:border-primary focus:ring-0 px-3 py-3 transition-colors outline-none text-on-surface rounded-t-lg"
                />
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowCreateLesson(false)} className="flex-1 py-3 rounded-full border-2 border-outline/30 text-on-surface font-semibold hover:bg-surface-container-high transition-colors">Cancel</button>
